import{_ as e,o as s,c as o,a0 as n}from"./chunks/framework.BjpW4enL.js";const u=JSON.parse('{"title":"Epistemic Bridge — Grafo Multi-Relacional com Consciência Epistemológica","description":"","frontmatter":{},"headers":[],"relativePath":"30_Ciencia_e_Topologia/epistemic-bridge.md","filePath":"30_Ciencia_e_Topologia/epistemic-bridge.md","lastUpdated":1783623176000}'),i={name:"30_Ciencia_e_Topologia/epistemic-bridge.md"};function t(d,a,r,c,p,l){return s(),o("div",null,[...a[0]||(a[0]=[n(`<h1 id="epistemic-bridge-—-grafo-multi-relacional-com-consciencia-epistemologica" tabindex="-1">Epistemic Bridge — Grafo Multi-Relacional com Consciência Epistemológica <a class="header-anchor" href="#epistemic-bridge-—-grafo-multi-relacional-com-consciencia-epistemologica" aria-label="Permalink to &quot;Epistemic Bridge — Grafo Multi-Relacional com Consciência Epistemológica&quot;">​</a></h1><p><strong>Tipo:</strong> Conceito / Research Note<br><strong>Data:</strong> 25 Jun. 2026<br><strong>Status:</strong> Pensamento — prototipação futura</p><hr><h2 id="_1-motivacao" tabindex="-1">1. Motivação <a class="header-anchor" href="#_1-motivacao" aria-label="Permalink to &quot;1. Motivação&quot;">​</a></h2><p>O NEXUS hoje opera com <strong>níveis de abstração</strong> (L0–L3) em um único eixo. Código é ingerido, abstraído semanticamente, e navegado topologicamente. Mas esse modelo unidimensional não captura a <strong>natureza epistemológica</strong> dos dados — quão certos estamos sobre cada informação, e como atravessar diferentes regimes de certeza dentro do mesmo grafo.</p><p>Este documento propõe um modelo onde <strong>cada nó e cada aresta carrega estado epistêmico</strong>, e a navegação entre domínios heterogêneos (código legado, schema SQL arbitrário, hipóteses de LLM) é mediada por <strong>pontes epistemológicas</strong>.</p><hr><h2 id="_2-o-problema" tabindex="-1">2. O Problema <a class="header-anchor" href="#_2-o-problema" aria-label="Permalink to &quot;2. O Problema&quot;">​</a></h2><h3 id="_2-1-cenario-concreto" tabindex="-1">2.1 Cenário Concreto <a class="header-anchor" href="#_2-1-cenario-concreto" aria-label="Permalink to &quot;2.1 Cenário Concreto&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nó A: schema SQL arbitrário, criado por LLM (epistemic = speculative)</span></span>
<span class="line"><span>Nó B: schema legado imutável, mal otimizado, sem RLS (epistemic = fact, cohesion = low)</span></span></code></pre></div><p>Como caminhar de A para B com rigor? A aresta direta A→B tem baixa confiança (<code>semantic_bridge</code> com <code>certainty ≈ 0.2</code>). Mas um caminho via mediador:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → (part_of) → Domain_A (fact) → (depends_on) → Domain_B (fact) → (part_of) → B (fact)</span></span></code></pre></div><p>Tem <code>certainty = 1.0</code> em cada aresta, mesmo que o caminho seja mais longo. <strong>O rigor do caminho depende do pior elo, não do mais curto.</strong></p><h3 id="_2-2-insuficiencia-do-modelo-atual" tabindex="-1">2.2 Insuficiência do Modelo Atual <a class="header-anchor" href="#_2-2-insuficiencia-do-modelo-atual" aria-label="Permalink to &quot;2.2 Insuficiência do Modelo Atual&quot;">​</a></h3><p>O T4 hoje tem 4 tipos de aresta (<code>part_of</code>, <code>depends_on:imports</code>, <code>semantic_bridge</code>, <code>contradicts</code>) e 3 eixos de projeção (<code>criteria × file_type × project</code>). Não há:</p><ul><li>Metadado epistêmico no nó (quão certo estamos deste dado?)</li><li>Metadado de coesão (quão bem estruturado é este domínio?)</li><li>Pontes entre domínios com semântica de confiança</li><li>Caminhada parametrizada por <code>min_certainty</code></li></ul><hr><h2 id="_3-o-modelo" tabindex="-1">3. O Modelo <a class="header-anchor" href="#_3-o-modelo" aria-label="Permalink to &quot;3. O Modelo&quot;">​</a></h2><h3 id="_3-1-episteme-como-eixo-de-projecao" tabindex="-1">3.1 Episteme como Eixo de Projeção <a class="header-anchor" href="#_3-1-episteme-como-eixo-de-projecao" aria-label="Permalink to &quot;3.1 Episteme como Eixo de Projeção&quot;">​</a></h3><p>Cada nó ganha dois novos campos:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Node</span></span>
<span class="line"><span>├── domain: code | schema | document | hypothesis | bridge</span></span>
<span class="line"><span>├── epistemic: fact | inferred | hypothesized | speculative</span></span>
<span class="line"><span>└── cohesion: high (constraints, types, AST) | medium (ORM, semi-estruturado) | low (bruto, sem schema)</span></span></code></pre></div><p>O eixo <code>epistemic</code> forma uma escala:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fact ───→ inferred ───→ hypothesized ───→ speculative</span></span>
<span class="line"><span>  ↑            ↑              ↑                ↑</span></span>
<span class="line"><span>  observado    deduzido       proposto         imaginado</span></span>
<span class="line"><span>  (parser,     (LLM sobre     (LLM sobre       (LLM livre,</span></span>
<span class="line"><span>   SQL DDL)     evidência)     padrão)           brainstorming)</span></span></code></pre></div><h3 id="_3-2-tensor-de-distancia" tabindex="-1">3.2 Tensor de Distância <a class="header-anchor" href="#_3-2-tensor-de-distancia" aria-label="Permalink to &quot;3.2 Tensor de Distância&quot;">​</a></h3><p>A distância entre dois nós não é um escalar — é um <strong>tensor quadridimensional</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dist(A, B) = (</span></span>
<span class="line"><span>    hops,              # contagem de arestas no caminho</span></span>
<span class="line"><span>    min_certainty,     # pior certainty entre todas as arestas</span></span>
<span class="line"><span>    epistemic_delta,   # custo de atravessar regimes de certeza:</span></span>
<span class="line"><span>                       #   fact→fact = 0.0</span></span>
<span class="line"><span>                       #   fact→speculative = 0.7</span></span>
<span class="line"><span>                       #   speculative→fact = 0.9 (sobe o rigor)</span></span>
<span class="line"><span>    cohesion_delta     # custo de atravessar coesão:</span></span>
<span class="line"><span>                       #   high→high = 0.0</span></span>
<span class="line"><span>                       #   high→low = 0.4</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>O consumidor (LLM, query) especifica restrições:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/query {</span></span>
<span class="line"><span>  &quot;text&quot;: &quot;como este schema se relaciona com o código legado?&quot;,</span></span>
<span class="line"><span>  &quot;min_certainty&quot;: 0.7,</span></span>
<span class="line"><span>  &quot;max_hops&quot;: 5</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>O runtime filtra caminhos que não atendem, e do que sobra, escolhe o mais curto ou o de maior <code>min_certainty</code> (parametrizável).</p><h3 id="_3-3-bridge-schema" tabindex="-1">3.3 Bridge Schema <a class="header-anchor" href="#_3-3-bridge-schema" aria-label="Permalink to &quot;3.3 Bridge Schema&quot;">​</a></h3><p>Um nó do tipo <code>domain: bridge</code> serve como <strong>mediador epistemológico</strong> entre dois domínios que não podem (ou não devem) se conectar diretamente:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bridge_A_B</span></span>
<span class="line"><span>├── domain: bridge</span></span>
<span class="line"><span>├── epistemic: hypothesized (criado por LLM ou admin)</span></span>
<span class="line"><span>├── schema: mapping</span></span>
<span class="line"><span>│   ├── coluna_A → coluna_B</span></span>
<span class="line"><span>│   ├── conceito_X → conceito_Y</span></span>
<span class="line"><span>│   └── certainty: 0.8 (validado manualmente)</span></span>
<span class="line"><span>└── edges:</span></span>
<span class="line"><span>    → Nó_A via semantic_bridge, certainty=0.8</span></span>
<span class="line"><span>    → Nó_B via semantic_bridge, certainty=0.8</span></span></code></pre></div><p>Propriedades:</p><ul><li>A bridge é <strong>verificável</strong>: um agente pode auditá-la e aumentar/diminuir <code>certainty</code></li><li>A bridge é <strong>mutável</strong>: se o schema do domínio A muda, a bridge pode ser revalidada</li><li>A bridge é <strong>decaível</strong> (ADR-0021): se ninguém atravessa, <code>decay_score</code> aumenta, e a bridge pode ser removida</li></ul><p>Vantagem sobre aresta direta A→B:</p><table tabindex="0"><thead><tr><th></th><th>Aresta direta</th><th>Via Bridge</th></tr></thead><tbody><tr><td>Acoplamento</td><td>A e B precisam se conhecer</td><td>A e B não sabem um do outro</td></tr><tr><td>Manutenção</td><td>Mudança em A quebra A→B</td><td>Bridge absorve a mudança</td></tr><tr><td>Auditoria</td><td>Sem ponto de verificação</td><td>Bridge é auditável</td></tr><tr><td>Reuso</td><td>Só A→B serve</td><td>Bridge pode conectar N domínios</td></tr></tbody></table><h3 id="_3-4-exemplo-de-caminhada" tabindex="-1">3.4 Exemplo de Caminhada <a class="header-anchor" href="#_3-4-exemplo-de-caminhada" aria-label="Permalink to &quot;3.4 Exemplo de Caminhada&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LLM: &quot;como este schema arbitrário se relaciona com o sistema legado?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Query busca seed em T3 (Qdrant) → encontra Nó_A (speculative, cohesion=low)</span></span>
<span class="line"><span>2. T4 expande: Nó_A → (part_of) → Domain_A (fact, cohesion=high)</span></span>
<span class="line"><span>3. T4 expande: Domain_A → (depends_on) → Domain_B (fact, cohesion=low)</span></span>
<span class="line"><span>   → caminho directo, min_certainty=1.0, epistemic_delta=0.0 (fact→fact)</span></span>
<span class="line"><span>4. T4 expande: Domain_B → (part_of) → Nó_B (fact, cohesion=low)</span></span>
<span class="line"><span>5. Resultado: caminho com 3 hops, min_certainty=1.0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Alternativa:</span></span>
<span class="line"><span>1. T4 expande: Nó_A → (semantic_bridge) → Bridge_A_B → Nó_B</span></span>
<span class="line"><span>   → 2 hops, min_certainty=0.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>O LLM escolhe: caminho mais rigoroso (fact→fact, certainty=1.0, 3 hops)</span></span>
<span class="line"><span>ou caminho mais curto (via bridge, certainty=0.8, 2 hops).</span></span></code></pre></div><hr><h2 id="_4-relacao-com-adrs-existentes" tabindex="-1">4. Relação com ADRs Existentes <a class="header-anchor" href="#_4-relacao-com-adrs-existentes" aria-label="Permalink to &quot;4. Relação com ADRs Existentes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Componente</th><th>ADR</th><th>Papel</th></tr></thead><tbody><tr><td><code>epistemic</code> como campo do nó</td><td>0025 (Vector Typing)</td><td>Extensão do typing por projeção: cada eixo epistêmico pode ter seu próprio espaço vetorial</td></tr><tr><td><code>certainty</code> como campo da aresta</td><td>0024 (Heat Propagation)</td><td>Heat pode servir como proxy de certainty validada por uso</td></tr><tr><td><code>decay_score</code> em pontes não usadas</td><td>0021 (Forgetful Swarm)</td><td>Pontes que ninguém atravessa decaem e desaparecem</td></tr><tr><td>Bridge como domínio separado</td><td>0003 (Nomad Workers)</td><td><code>NomadBridge</code> é um novo worker que observa pares de domínios e propõe pontes</td></tr><tr><td>Caminhada por <code>part_of</code></td><td>0002 (Operadores T4)</td><td><code>project(epistemic=fact)</code> projeta subgrafo apenas de nós com certeza alta</td></tr><tr><td>Parametrização <code>min_certainty</code></td><td>0002</td><td>Novo parâmetro nos operadores de projeção e expansão</td></tr></tbody></table><hr><h2 id="_5-fractal-e-auto-similaridade" tabindex="-1">5. Fractal e Auto-Similaridade <a class="header-anchor" href="#_5-fractal-e-auto-similaridade" aria-label="Permalink to &quot;5. Fractal e Auto-Similaridade&quot;">​</a></h2><p>A intuição original: o padrão epistêmico se repete em diferentes escalas de escopo.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Escopo linha (L0)         Escopo função (L1)        Escopo módulo (L3)</span></span>
<span class="line"><span>fact ──→ inferred          fact ──→ inferred          fact ──→ inferred</span></span>
<span class="line"><span>│                            │                            │</span></span>
<span class="line"><span>▼                            ▼                            ▼</span></span>
<span class="line"><span>syntax error → provável     docstring ausente →          módulo sem ADR →</span></span>
<span class="line"><span>bug (inferred)              propósito inferido            propósito especulado</span></span></code></pre></div><p>O mesmo padrão <code>fact → inferred → hypothesized</code> aparece em cada nível, apenas com granularidade diferente. Isso é <strong>auto-similaridade</strong> — uma propriedade fractal.</p><p>Mas <strong>implementar fractais literais</strong> (dimensão de Hausdorff, iterações de função) seria overengineering neste estágio. O tensor quadridimensional já captura a essência:</p><ul><li><code>hops</code>: a escala (quantos níveis de escopo atravessar?)</li><li><code>epistemic_delta</code>: o custo de mudar de regime de certeza (a &quot;densidade&quot; da transição)</li><li><code>cohesion_delta</code>: a qualidade estrutural do domínio (a &quot;rugosidade&quot; do espaço)</li></ul><p>O que o tensor NÃO captura (e fractais fariam) é a <strong>predição de comportamento em escala não observada</strong>. Se conhecemos o padrão epistêmico em L0–L2, poderíamos inferir o comportamento em L5 sem precisar ingerir dados daquele nível. Isso é um <strong>problema de pesquisa aberto</strong> para o NEXUS.</p><hr><h2 id="_6-o-que-nao-e-para-nao-confundir" tabindex="-1">6. O que NÃO é (para não confundir) <a class="header-anchor" href="#_6-o-que-nao-e-para-nao-confundir" aria-label="Permalink to &quot;6. O que NÃO é (para não confundir)&quot;">​</a></h2><ul><li><strong>Não é um novo ADR.</strong> Nenhuma decisão foi tomada. É uma exploração.</li><li><strong>Não substitui T3/T4.</strong> É uma camada conceitual sobre T4.</li><li><strong>Não exige mudança no Qdrant.</strong> Qdrant continua servindo <code>seeds</code> por proximidade. A navegação epistemológica é no T4.</li><li><strong>Não resolve migrations SQL tradicionais.</strong> Bridge é uma alternativa semântica, não substituta de DDL.</li></ul><hr><h2 id="_7-proximos-passos-quando-pertinente" tabindex="-1">7. Próximos Passos (Quando Pertinente) <a class="header-anchor" href="#_7-proximos-passos-quando-pertinente" aria-label="Permalink to &quot;7. Próximos Passos (Quando Pertinente)&quot;">​</a></h2><ol><li>Adicionar campo <code>epistemic</code> à tabela <code>abstractions</code> (text check: &#39;fact&#39;,&#39;inferred&#39;,&#39;hypothesized&#39;,&#39;speculative&#39;)</li><li>Adicionar campo <code>certainty</code> à tabela <code>agent_links</code> (float 0.0–1.0)</li><li>Prototipar <code>NomadBridge</code>: observa dois domínios, propõe <code>semantic_bridge</code> com certainty</li><li>Estender <code>/query</code> com parâmetros <code>min_certainty</code> e <code>max_hops</code></li><li>Documentar casos de uso com bridges reais (schema legado → schema LLM)</li></ol><hr><blockquote><p><em>&quot;A distância entre dois pontos não é o que os separa, mas o que é preciso atravessar para entendê-los.&quot;</em><br> — Nota de arquitetura, 25 Jun. 2026</p></blockquote>`,57)])])}const h=e(i,[["render",t]]);export{u as __pageData,h as default};
